import{_ as t,o,c as r,ae as n}from"./chunks/framework.BntNH3M0.js";const i="/command-helper/wiki/1.png",a="/command-helper/wiki/2.png",s="/command-helper/wiki/3.png",l="/command-helper/wiki/4.png",c="/command-helper/wiki/5.png",p="/command-helper/wiki/6.png",w=JSON.parse('{"title":"How to Get Your Gemini API Key","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),h={name:"index.md"};function g(u,e,d,y,m,k){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="how-to-get-your-gemini-api-key" tabindex="-1">How to Get Your Gemini API Key <a class="header-anchor" href="#how-to-get-your-gemini-api-key" aria-label="Permalink to &quot;How to Get Your Gemini API Key&quot;">​</a></h1><p>To use the <strong>Ask Assistant</strong> feature in Command Helper, you need a &quot;Gemini API Key&quot;. Think of it as a special password that lets your game talk to Google&#39;s AI.</p><p>Don&#39;t worry if you&#39;ve never done this before! Just follow these exact steps slowly, and you&#39;ll be done in 5 minutes.</p><h2 id="getting-your-key" tabindex="-1">Getting Your Key <a class="header-anchor" href="#getting-your-key" aria-label="Permalink to &quot;Getting Your Key&quot;">​</a></h2><p><strong>Step 1: Go to the Google AI Studio website</strong><br> Click this exact link to open the page: <a href="https://aistudio.google.com/" target="_blank" rel="noreferrer">https://aistudio.google.com/</a></p><p><strong>Step 2: Sign in to Google</strong><br> If you aren&#39;t already logged in, it will ask you to sign in with your regular Google account (the same one you use for YouTube or Gmail).</p><p><strong>Step 3: Accept the Terms (if asked)</strong><br> If this is your first time here, a welcome screen might pop up. Check the boxes to agree to the terms and click the <strong>Continue</strong> button.</p><p><strong>Step 4: Click &quot;Create API Key&quot;</strong><img src="'+i+'" alt="Step 4 screenshot"></p><p>Look at the bottom-left corner of the screen. Above the settings button, which is above your profile picture, there should be a <strong>Get API key</strong> button. Click it!</p><p><strong>Step 5: Create a new project</strong><br><img src="'+a+'" alt="Step 5 screenshot A"></p><p>In the top-right corner, click the <strong>Create API key</strong> button. A popup will appear where you need to give your API key a name, then choose a Cloud project for it. If you already have one, select it. If you don&#39;t have one yet, click the dropdown and then the <strong>Create project</strong> button.</p><p><img src="'+s+'" alt="Step 5 screenshot B"></p><p>Fill out the form. The system will automatically use the newly created project for your API key. After that, click the <strong>Create key</strong> button.</p><p><img src="'+l+'" alt="Step 5 screenshot C"></p><p><strong>Step 6: Copy your key</strong><br> A new row should appear. At the start of the row, there will be blue text like <code>...XXXX</code>. Click on it. Those are the final 4 characters of your API key.</p><p><img src="'+c+'" alt="Step 6 screenshot A"></p><p>Then, a window will show your new API key. It is a very long text that starts with <code>AIza...</code>. Click the <strong>Copy</strong> button right next to it.</p><p><img src="'+p+'" alt="Step 6 screenshot B"></p><p><em>(Warning: Treat this like a real password. Do not send this text to your friends or post it on the internet!)</em></p><p><strong>Step 7: Paste it into Minecraft</strong><br> Open Minecraft, go to the Command Helper mod, open the Ask Assistant window, and paste (<code>Ctrl+V</code>) this long text into the API key text box.</p><hr><h2 id="geolocational-restrictions" tabindex="-1">Geolocational restrictions <a class="header-anchor" href="#geolocational-restrictions" aria-label="Permalink to &quot;Geolocational restrictions&quot;">​</a></h2><p><strong>Are you living in the European Union, the UK, or Switzerland?</strong> If yes, your API key will <strong>not</strong> work immediately. If you try to use it, the mod will show an <code>HTTP 429</code> error.</p><p><strong>Why does this happen?</strong><br> Because of European privacy laws, Google does not allow free AI usage without verifying who you are. They require you to add a bank card to your account to prove you are a real person and to unlock the service.</p><p><strong>Will they take my money?</strong><br> No! As long as you are only using this key for yourself in Minecraft, you will stay in the &quot;Free Tier&quot; limits. But the system <em>needs</em> the card attached, otherwise the limit is locked at zero.</p><h3 id="here-is-exactly-how-to-fix-the-error" tabindex="-1">Here is exactly how to fix the error: <a class="header-anchor" href="#here-is-exactly-how-to-fix-the-error" aria-label="Permalink to &quot;Here is exactly how to fix the error:&quot;">​</a></h3><p><strong>Step 1: Go to the Google Cloud Console</strong><br> Click this link: <a href="https://console.cloud.google.com/billing" target="_blank" rel="noreferrer">https://console.cloud.google.com/billing</a></p><p><strong>Step 2: Create a Billing Account</strong><br> Click on <strong>Manage Billing Accounts</strong> or <strong>Link a Billing Account</strong>. Then click <strong>Create Account</strong>.</p><p><strong>Step 3: Fill in your details</strong><br> It will ask for your country, address, and your bank card details. Fill everything out honestly.</p><p><strong>Step 4: Link it to your project</strong><br> Make sure this new billing account is connected to the <strong>Generative Language Client</strong> project (the project you created in Part 1).</p><p><strong>Step 5: Restart your game</strong><br> Close Minecraft completely and open it again. Try the Ask Assistant button now. It should work perfectly!</p><blockquote><p>Pro tip: If you want to be 100% safe, you can look for the <strong>Budgets &amp; alerts</strong> menu in the Google Cloud Billing page and set a budget of <code>$1.00</code>. This way, you will get an email if you ever accidentally use too much.</p></blockquote>',32)])])}const b=t(h,[["render",g]]);export{w as __pageData,b as default};
